// ============================================================
//  DIVINE RATIONS — Active Effects System
// ============================================================
let activeEffects = []; // [{effectType, expiresAt, itemId, label}]

// Divine Rations icon (base64 embedded PNG)
const DIVINE_RATIONS_IMG = "data:image/png;base64,";

function isEffectActive(effectType) {
  cleanupExpiredEffects();
  return activeEffects.some(e => e.effectType === effectType && e.expiresAt > Date.now());
}

function cleanupExpiredEffects() {
  const now = Date.now();
  const before = activeEffects.length;
  activeEffects = activeEffects.filter(e => e.expiresAt > now);
  if(activeEffects.length !== before) {
    updateDivineRationsIndicator();
  }
}

function useDivineRations() {
  const qty = specialItemInventory['divine_rations'] || 0;
  if(qty <= 0) return;

  const DURATION_MS = 24 * 60 * 60 * 1000; // 24 hours
  const existing = activeEffects.find(e => e.effectType === 'zero_food_consumption');

  if(existing) {
    // Extend duration
    existing.expiresAt += DURATION_MS;
  } else {
    activeEffects.push({
      effectType: 'zero_food_consumption',
      expiresAt: Date.now() + DURATION_MS,
      itemId: 'divine_rations',
      label: 'Divine Rations'
    });
  }

  specialItemInventory['divine_rations'] = qty - 1;
  saveSpecialItems();
  saveGame();
  updateDivineRationsIndicator();

  // Re-render inventory if open
  const content = document.getElementById('inventoryContent');
  if(content && document.getElementById('inventoryPanel')?.classList.contains('show')) {
    renderInventoryTab('general');
  }
}

function getDivineRationsTimeLeft() {
  const eff = activeEffects.find(e => e.effectType === 'zero_food_consumption');
  if(!eff) return null;
  const ms = eff.expiresAt - Date.now();
  if(ms <= 0) return null;
  const h = Math.floor(ms / 3600000);
  const m = Math.floor((ms % 3600000) / 60000);
  const s = Math.floor((ms % 60000) / 1000);
  return `${h}h ${String(m).padStart(2,'0')}m ${String(s).padStart(2,'0')}s`;
}

// ============================================================
//  ACTIVE EFFECTS BUTTON + PANEL (above music button)
// ============================================================
const EFFECT_BTN_ICON = "data:image/png;base64,";

let _effectsPanelOpen = false;

function updateDivineRationsIndicator() {
  const hasActive = activeEffects.some(e => e.expiresAt > Date.now());

  // ── Button ──
  let btn = document.getElementById('activeEffectsBtn');
  if(!btn) {
    btn = document.createElement('button');
    btn.id = 'activeEffectsBtn';
    btn.type = 'button';
    btn.style.cssText = `
      position:fixed; right:20px; bottom:120px; z-index:99999999;
      width:20px; height:20px; padding:0; margin:0;
      background:transparent; border:0; cursor:pointer;
      pointer-events:auto; display:none;
    `;
    btn.innerHTML = `<img src="${EFFECT_BTN_ICON}" style="width:35px;height:35px;display:block;">
      <span id="effectsBadge" style="position:absolute;top:-4px;right:-4px;background:#d4af37;color:#1a1408;font-size:10px;font-weight:bold;min-width:16px;height:16px;border-radius:8px;display:flex;align-items:center;justify-content:center;padding:0 3px;"></span>`;
    btn.addEventListener('click', toggleEffectsPanel);
    document.body.appendChild(btn);
  }
  btn.style.display = hasActive ? 'block' : 'none';

  // Update badge count
  const badge = document.getElementById('effectsBadge');
  if(badge) {
    const count = activeEffects.filter(e => e.expiresAt > Date.now()).length;
    badge.textContent = count > 0 ? count : '';
    badge.style.display = count > 0 ? 'flex' : 'none';
  }

  // If no active effects, hide panel too
  if(!hasActive) {
    const panel = document.getElementById('activeEffectsPanel');
    if(panel) panel.style.display = 'none';
    _effectsPanelOpen = false;
  }

  // Update panel contents if open
  if(_effectsPanelOpen) renderEffectsPanel();
}

function toggleEffectsPanel() {
  _effectsPanelOpen = !_effectsPanelOpen;
  let panel = document.getElementById('activeEffectsPanel');

  if(!panel) {
    panel = document.createElement('div');
    panel.id = 'activeEffectsPanel';
    panel.style.cssText = `
      position:fixed; right:60px; bottom:200px; z-index:99999998;
      background:rgba(20,18,14,0.95); border:1px solid #5a4a2a;
      border-radius:10px; padding:0; min-width:260px; max-width:300px;
      display:none; box-shadow:0 6px 24px rgba(0,0,0,0.7);
      font-family:'Segoe UI',system-ui,sans-serif;
    `;
    document.body.appendChild(panel);
  }

  if(_effectsPanelOpen) {
    panel.style.display = 'block';
    renderEffectsPanel();
  } else {
    panel.style.display = 'none';
  }
}

function renderEffectsPanel() {
  const panel = document.getElementById('activeEffectsPanel');
  if(!panel) return;

  const now = Date.now();
  const effects = activeEffects.filter(e => e.expiresAt > now);

  if(effects.length === 0) {
    panel.style.display = 'none';
    _effectsPanelOpen = false;
    return;
  }

  // Header
let html = `<div style="padding:10px 14px 6px; border-bottom:0; display:flex; align-items:center; gap:8px; background:transparent;">
    <img src="${EFFECT_BTN_ICON}" style="width:22px;height:22px;">
    <span style="color:#d4af37; font-weight:bold; font-size:13px;">Active Effects</span>
    <span style="color:#888; font-size:11px; margin-left:auto;">${effects.length}</span>
  </div>`;

  // Effect items
  effects.forEach(eff => {
    const ms = eff.expiresAt - now;
    const d = Math.floor(ms / 86400000);
    const h = Math.floor((ms % 86400000) / 3600000);
    const m = Math.floor((ms % 3600000) / 60000);
    const s = Math.floor((ms % 60000) / 1000);
    const timeStr = d > 0
      ? `${d}d ${h}h ${String(m).padStart(2,'0')}m ${String(s).padStart(2,'0')}s`
      : `${h}h ${String(m).padStart(2,'0')}m ${String(s).padStart(2,'0')}s`;

    // Map effectType to display info
    let icon = DIVINE_RATIONS_IMG;
    let name = eff.label || 'Unknown Effect';
    let desc = '';
    if(eff.effectType === 'zero_food_consumption') {
      desc = 'Food from the Gods to quell the appetite of your troops. Eliminates troops\' upkeep.';
    }

    html += `
  <div style="padding:10px 14px; display:flex; gap:10px; align-items:flex-start; border-bottom:0; background:transparent;">
        <img src="${icon}" style="width:44px; height:44px; border-radius:6px; border:1px solid #5a4a2a; object-fit:cover; flex-shrink:0;">
        <div style="flex:1; min-width:0;">
          <div style="display:flex; align-items:center; gap:8px; margin-bottom:3px;">
            <span style="color:#e8d8b0; font-weight:bold; font-size:12px;">${name}</span>
            <span style="color:#f5a623; font-size:11px; font-family:monospace; font-weight:bold; margin-left:auto; white-space:nowrap;">${timeStr}</span>
          </div>
          <div style="color:#999; font-size:11px; line-height:1.4;">${desc}</div>
        </div>
      </div>`;
  });

  panel.innerHTML = html;
}

// Update effects timer every second
setInterval(function() {
  const hasActive = activeEffects.some(e => e.expiresAt > Date.now());
  // Update button visibility
  const btn = document.getElementById('activeEffectsBtn');
  if(btn) btn.style.display = hasActive ? 'block' : 'none';
  // Update panel if open
  if(_effectsPanelOpen && hasActive) renderEffectsPanel();
  if(!hasActive && _effectsPanelOpen) {
    const panel = document.getElementById('activeEffectsPanel');
    if(panel) panel.style.display = 'none';
    _effectsPanelOpen = false;
  }
}, 1000);

// Close effects panel when clicking outside
document.addEventListener('click', function(e) {
  if(!_effectsPanelOpen) return;
  const panel = document.getElementById('activeEffectsPanel');
  const btn = document.getElementById('activeEffectsBtn');
  if(panel && btn && !panel.contains(e.target) && !btn.contains(e.target)) {
    panel.style.display = 'none';
    _effectsPanelOpen = false;
  }
});

