// Coordenadas de la ciudad del jugador (se asignan al cargar save o al crear cuenta)
// ✅ Map constants (shared across all map functions)
const MAP_GRID_SIZE = 50;       // 50x50 = 2500 zones
const MAP_GRID_CELL = 100 / MAP_GRID_SIZE;
const MAP_COORD_MAX = 500;      // coordinate range 0-500
const MAP_TILES = 5;            // 5x5 visual tiles

const playerCity = {
  coordX: Math.floor(Math.random() * (MAP_COORD_MAX - 20)) + 10,
  coordY: Math.floor(Math.random() * (MAP_COORD_MAX - 20)) + 10,
  name: "My City"
};

// Otras ciudades de jugadores (se cargan del servidor)
let otherPlayerCities = [];

// Fetch all player cities from server
async function fetchPlayerCities(){
  try {
    const token = localStorage.getItem('ATLANTIS_TOKEN');
    if(!token) return;
    const res = await fetch('/api/game/cities', {
      headers: { 'Authorization': 'Bearer ' + token }
    });
    const data = await res.json();
    if(data.ok && Array.isArray(data.cities)){
      const ses = getSession();
      const myUser = ses?.user?.toLowerCase();
      otherPlayerCities = data.cities.filter(c => c.username?.toLowerCase() !== myUser);
      console.log(`🌍 Loaded ${otherPlayerCities.length} other player cities`);
      // Re-render map if already visible
      if(mapZones.length > 0){
        addOtherPlayerZones();
        renderMapZones();
      }
    }
  } catch(e){
    console.warn('⚠️ Could not fetch player cities:', e);
  }
}

// Add other players' fortresses to mapZones
function addOtherPlayerZones(){
  // Remove old other-player zones
  mapZones = mapZones.filter(z => !z.id.startsWith('other_player_'));
  
  // uses global MAP_GRID_SIZE
  // uses global MAP_GRID_CELL
  
  otherPlayerCities.forEach((city, idx) => {
    const col = Math.floor((city.coordX / MAP_COORD_MAX) * MAP_GRID_SIZE);
    const row = Math.floor((city.coordY / MAP_COORD_MAX) * MAP_GRID_SIZE);
    const x = col * MAP_GRID_CELL + MAP_GRID_CELL / 2;
    const y = row * MAP_GRID_CELL + MAP_GRID_CELL / 2;
    
    // ✅ Remove any existing zone at this grid cell
    mapZones = mapZones.filter(z => {
      if(z.type === 'fortress') return true; // never remove own fortress
      const zCol = Math.floor((z.x - MAP_GRID_CELL / 2) / MAP_GRID_CELL + 0.5);
      const zRow = Math.floor((z.y - MAP_GRID_CELL / 2) / MAP_GRID_CELL + 0.5);
      return !(zCol === col && zRow === row);
    });
    
    mapZones.push({
      id: `other_player_${idx}`,
      typeId: 'other_fortress',
      name: city.username || 'Unknown',
      icon: 'assets/Fortress.png',
      type: 'other_fortress',
      level: city.fortressLevel || 1,
      x: x,
      y: y,
      coordX: city.coordX,
      coordY: city.coordY,
      ownerName: city.username
    });
  });
  console.log(`🏰 Added ${otherPlayerCities.length} other player fortresses to map`);
}

