// ✅ carga (si existe) y pisa los defaults
function loadGame(){
  try{
    // ✅ usar el save más reciente entre principal y backup
    const rawMain = localStorage.getItem(SAVE_KEY);
    if(!rawMain) return false;

    // ✅ descomprimir si está comprimido (LZString), o parsear directo si es save viejo
    let raw = rawMain;
    try {
      const decompressed = LZString.decompress(rawMain);
      if(decompressed && decompressed.length > 0) raw = decompressed;
    } catch(e) { /* save viejo sin comprimir, usar raw directo */ }

    const data = JSON.parse(raw);

    // recursos
    if(data.playerResources){
      Object.keys(playerResources).forEach(k=>{
        if(typeof data.playerResources[k] !== "undefined"){
          playerResources[k] = data.playerResources[k];
        }
      });
    }

    // ✅ compat: si venís de un save viejo, aseguramos power
    if(typeof playerResources.power !== "number") playerResources.power = 0;

    // builtSlots (sin runtime objects)
    if(data.builtSlots){
      Object.keys(builtSlots).forEach(k => delete builtSlots[k]);
      Object.entries(data.builtSlots).forEach(([slotId, v])=>{
        builtSlots[Number(slotId)] = {
          state: v.state,
          building: v.building,
          level: v.level ?? 0,
          fixed: !!v.fixed,
          endsAt: v.endsAt ?? null,
          gifEl: null,
          sprite: null,
          levelBadge: null,
          hoverOutline: null,
          _timer: null
        };
      });
    }

    // ✅ NUEVO: cargar builtFieldSlots (con timer real + upgrade)
    if(data.builtFieldSlots){
      Object.keys(builtFieldSlots).forEach(k => delete builtFieldSlots[k]);
      Object.entries(data.builtFieldSlots).forEach(([slotId, v])=>{
        builtFieldSlots[Number(slotId)] = {
          state: v.state,
          building: v.building,
          level: v.level ?? 0,
          endsAt: v.endsAt ?? null,
          // runtime
          gifEl: null,
          sprite: null,
          _timer: null,
          badgeEl: null,
          levelBadge: null
        };
      });
    }

    // ✅ NUEVO: cargar niveles de investigación
    if(data.researchLevels){
      Object.assign(researchLevels, data.researchLevels);
    }

    // cargar investigaciones en curso
    if(data.activeResearches && Array.isArray(data.activeResearches)){
      activeResearches = data.activeResearches;
    }

    // cargar entrenamientos de tropas en progreso
    if(data.activeTroopTrainings && Array.isArray(data.activeTroopTrainings)){
      activeTroopTrainings = data.activeTroopTrainings;
    }

    // cargar cantidades de tropas entrenadas
    if(data.troopQuantities){
      TROOPS.forEach(t => {
        if(typeof data.troopQuantities[t.id] !== "undefined"){
          t.have = data.troopQuantities[t.id];
        }
      });
    }

    // Cargar piezas de armadura del dragón
    if(data.playerDragonArmor){
      Object.assign(playerDragonArmor, data.playerDragonArmor);
    }

    // ✅ guardar snapshot de inventarios para aplicar cuando cada sistema se inicialice
    if(!window._savedInventories) window._savedInventories = {};
    if(data.accInventory)          window._savedInventories.accInventory          = data.accInventory;
    if(data.chestInventory)        window._savedInventories.chestInventory        = data.chestInventory;
    if(data.resourcePackInventory) window._savedInventories.resourcePackInventory = data.resourcePackInventory;
    if(data.resPackInventory)      window._savedInventories.resPackInventory      = data.resPackInventory;
    if(data.specialItemInventory)  window._savedInventories.specialItemInventory  = data.specialItemInventory;
    if(typeof data.fortunaMedallions === "number") window._savedInventories.fortunaMedallions = data.fortunaMedallions;

    // ✅ Cargar activeEffects (Divine Rations etc.)
    if(Array.isArray(data.activeEffects)){
      activeEffects = data.activeEffects.filter(e => e.expiresAt > Date.now());
    }

    // ✅ restaurar posición del mapa (se aplica en initMapSystem)
    if(data.mapPosition && typeof data.mapPosition.x === "number"){
      window._savedMapPosition = { x: data.mapPosition.x, y: data.mapPosition.y };
    }

    // ✅ restaurar coordenadas de la ciudad del jugador
    if(data.playerCity && typeof data.playerCity.coordX === "number"){
      playerCity.coordX = data.playerCity.coordX;
      playerCity.coordY = data.playerCity.coordY;
    }

    console.log("💾✅ SAVE CARGADO", data);
    return true;
  }catch(err){
    console.warn("❌ Error cargando save:", err);
    return false;
  }
}

// ✅ Aplica datos de save (desde servidor o localStorage)
function _applyLoadedData(data){
  try{
    if(data.playerResources){
      Object.keys(playerResources).forEach(k=>{
        if(typeof data.playerResources[k] !== "undefined"){
          playerResources[k] = data.playerResources[k];
        }
      });
    }
    if(typeof playerResources.power !== "number") playerResources.power = 0;

    if(data.builtSlots){
      Object.keys(builtSlots).forEach(k => delete builtSlots[k]);
      Object.entries(data.builtSlots).forEach(([slotId, v])=>{
        builtSlots[Number(slotId)] = {
          state: v.state, building: v.building, level: v.level ?? 0,
          fixed: !!v.fixed, endsAt: v.endsAt ?? null,
          gifEl: null, sprite: null, levelBadge: null, hoverOutline: null, _timer: null
        };
      });
    }
    if(data.builtFieldSlots){
      Object.keys(builtFieldSlots).forEach(k => delete builtFieldSlots[k]);
      Object.entries(data.builtFieldSlots).forEach(([slotId, v])=>{
        builtFieldSlots[Number(slotId)] = {
          state: v.state, building: v.building, level: v.level ?? 0,
          endsAt: v.endsAt ?? null,
          gifEl: null, sprite: null, _timer: null, badgeEl: null, levelBadge: null
        };
      });
    }
    if(data.researchLevels) Object.assign(researchLevels, data.researchLevels);
    if(data.activeResearches && Array.isArray(data.activeResearches)) activeResearches = data.activeResearches;
    if(data.activeTroopTrainings && Array.isArray(data.activeTroopTrainings)) activeTroopTrainings = data.activeTroopTrainings;
    if(data.troopQuantities){
      TROOPS.forEach(t => {
        if(typeof data.troopQuantities[t.id] !== "undefined") t.have = data.troopQuantities[t.id];
      });
    }
    if(data.playerDragonArmor) Object.assign(playerDragonArmor, data.playerDragonArmor);
    if(!window._savedInventories) window._savedInventories = {};
    if(data.accInventory)          window._savedInventories.accInventory          = data.accInventory;
    if(data.chestInventory)        window._savedInventories.chestInventory        = data.chestInventory;
    if(data.resourcePackInventory) window._savedInventories.resourcePackInventory = data.resourcePackInventory;
    if(data.resPackInventory)      window._savedInventories.resPackInventory      = data.resPackInventory;
    if(data.specialItemInventory)  window._savedInventories.specialItemInventory  = data.specialItemInventory;
    if(typeof data.fortunaMedallions === "number") window._savedInventories.fortunaMedallions = data.fortunaMedallions;
    if(Array.isArray(data.activeEffects)) activeEffects = data.activeEffects.filter(e => e.expiresAt > Date.now());
    if(data.mapPosition && typeof data.mapPosition.x === "number") window._savedMapPosition = { x: data.mapPosition.x, y: data.mapPosition.y };
    if(data.playerCity && typeof data.playerCity.coordX === "number"){ playerCity.coordX = data.playerCity.coordX; playerCity.coordY = data.playerCity.coordY; }
    console.log('☁️✅ _applyLoadedData OK');
  }catch(err){
    console.warn('❌ Error en _applyLoadedData:', err);
  }
}

// ✅ guarda estado actual
// ✅ Merge seguro: usa 'current' si tiene datos, sino usa 'saved' como fallback
function _mergeInventory(current, saved) {
  if (!saved) return { ...current };
  const hasData = Object.values(current).some(v => v > 0);
  if (hasData) {
    // Tomar el máximo entre current y saved para no perder nada
    const merged = { ...saved };
    Object.keys(current).forEach(k => { merged[k] = Math.max(current[k] || 0, saved[k] || 0); });
    return merged;
  }
  // current está vacío — devolver saved para no perder items
  return { ...saved };
}

function saveGame(){
  try{
    const serialSlots = {};
    Object.entries(builtSlots).forEach(([slotId, v])=>{
      if(!v) return;

      const clean = {};
      Object.keys(v).forEach(k=>{
        if(!RUNTIME_FIELDS.includes(k)){
          clean[k] = v[k];
        }
      });

      serialSlots[slotId] = clean;
    });

    // ✅ NUEVO: serializar field (incluye endsAt/level)
    const serialFieldSlots = {};
    Object.entries(builtFieldSlots).forEach(([slotId, v])=>{
      if(!v) return;

      serialFieldSlots[slotId] = {
        state: v.state,
        building: v.building,
        level: v.level ?? 0,
        endsAt: v.endsAt ?? null
      };
    });

    // Guardar cantidades de tropas entrenadas
    const troopQuantities = {};
    TROOPS.forEach(t => { troopQuantities[t.id] = t.have || 0; });

    const payload = {
      savedAt: Date.now(),
      _username: getSession()?.user || 'Unknown',
      playerResources: { ...playerResources },
      builtSlots: serialSlots,
      builtFieldSlots: serialFieldSlots,
      researchLevels: { ...researchLevels },
      activeResearches: [...activeResearches],           // ✅ investigaciones en curso
      activeTroopTrainings: [...activeTroopTrainings],
      troopQuantities: troopQuantities,
      playerDragonArmor: { ...playerDragonArmor },
      // ✅ posición del mapa (para restaurar al recargar)
      mapPosition: { x: mapX, y: mapY },
      // ✅ coordenadas de la ciudad del jugador
      playerCity: { coordX: playerCity.coordX, coordY: playerCity.coordY },
      // ✅ inventarios consolidados en el save principal
      // Protección: nunca sobreescribir con vacío si ya había datos guardados
      accInventory:          _mergeInventory(accInventory,          window._savedInventories?.accInventory),
      chestInventory:        _mergeInventory(chestInventory,        window._savedInventories?.chestInventory),
      resourcePackInventory: _mergeInventory(resourcePackInventory, window._savedInventories?.resourcePackInventory),
      resPackInventory:      _mergeInventory(resPackInventory,      window._savedInventories?.resPackInventory),
      specialItemInventory:  _mergeInventory(specialItemInventory,  window._savedInventories?.specialItemInventory),
      fortunaMedallions:     (fortunaMedallions > 0 || !window._savedInventories?.fortunaMedallions)
                               ? fortunaMedallions
                               : window._savedInventories.fortunaMedallions,
      activeEffects:         activeEffects.filter(e => e.expiresAt > Date.now()) // ✅ Divine Rations etc.
    };

    const payloadStr = JSON.stringify(payload);
    // ✅ guardar en localStorage como backup local
    try {
      localStorage.setItem(SAVE_KEY, LZString.compress(payloadStr));
    } catch(quotaErr) {
      console.warn("⚠️ Quota excedida, limpiando keys viejas...");
      ['specialItems_v1','resPackInventory_v1','fortunaMedallions_v1',
       'chestInventory_v1','resourcePackInventory_v1','accInventory_v1',
       'ATLANTIS_MVP_SAVE_V1_BACKUP'].forEach(k => { try{ localStorage.removeItem(k); }catch(e){} });
      try {
        localStorage.setItem(SAVE_KEY, LZString.compress(payloadStr));
      } catch(e2) {
        console.error("❌ No se pudo guardar:", e2);
      }
    }
    // ✅ guardar en el servidor (Supabase)
    const token = localStorage.getItem('ATLANTIS_TOKEN');
    if(token){
      fetch('/api/game/save', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
        body: JSON.stringify({ saveData: payload })
      }).catch(e => console.warn('⚠️ No se pudo guardar en servidor:', e));
    }
  }catch(err){
    console.warn("❌ Error guardando:", err);
  }
}

function clearSave(){
  localStorage.removeItem(SAVE_KEY);
  console.log("🗑️ Save borrado");
}
function resetGameProgressOnly(){
  // 1) borrar SOLO el save del juego
  localStorage.removeItem(SAVE_KEY);

  // 2) si querés que también se vuelva a dar el starter pack,
  // descomentá estas 2 líneas:
  // localStorage.removeItem(STARTER_KEY);

  // 3) limpiar estados en memoria
  Object.keys(builtSlots).forEach(k => delete builtSlots[k]);
  Object.keys(builtFieldSlots).forEach(k => delete builtFieldSlots[k]);

  // 4) resetear recursos a defaults
  playerResources.wood = 2000000;
  playerResources.stone = 2000000;
  playerResources.iron = 2000000;
  playerResources.food = 2000000;
  playerResources.gold = 2000000;
  playerResources.poblacion = 0;
  playerResources.power = 0;

  // ✅ Clear active effects (Divine Rations etc.)
  activeEffects = [];
  updateDivineRationsIndicator();

  // 5) reponer prebuilt (fortress + egg)
  applyPrebuiltDefaults();

  // 6) refrescar UI + volver a dibujar sprites
  updateResourcesUI();

  if(window.cityScene){
    restoreVisualStateAfterLoad(); // redibuja city
  }
  if(window.fieldScene){
    window.fieldScene.restoreFieldVisualsAfterLoad?.(); // redibuja field
  }

  // 7) guardar el nuevo estado limpio
  saveGame();

  setSelection("✅ Progress reset (without logging out).");
}



/* ============================================================
   STARTER PACK (DOA-style)
============================================================ */
const STARTER_KEY = "ATLANTIS_STARTER_GIVEN_V1";

function giveStarterPackOnce(){
  if(localStorage.getItem(STARTER_KEY)) return;

  // ✅ pack inicial para avanzar (aunque capacity sea 0)
  playerResources.wood  += 2000;
  playerResources.stone += 2000;
  playerResources.iron  += 1000;
  playerResources.food  += 2000;
  playerResources.gold  += 500;

  // ✅ items iniciales en el inventario
  // Chronos Bag y Chronos Vault (se inicializan después, usamos timeout para asegurar que chestInventory ya esté listo)
  setTimeout(() => {
    giveChest('chronos_bag', 1);
    giveChest('chronos_vault', 1);
    giveMedallion(5);
  }, 500);

  localStorage.setItem(STARTER_KEY, "1");
  updateResourcesUI();
  saveGame();
}

