/* ✅ DESTROY BUILDING (City) */
document.addEventListener("click", (e)=>{
  const btn = e.target.closest(".cb-destroy");
  if(!btn) return;

  e.preventDefault();
  e.stopPropagation();

  const slotId = Number(btn.dataset.slot);
  closeModal();
  destroyBuilding(slotId);
});

/* ✅ DESTROY BUILDING (Field) */
document.addEventListener("click", (e)=>{
  const btn = e.target.closest(".cb-field-destroy");
  if(!btn) return;

  e.preventDefault();
  e.stopPropagation();

  const slotId = Number(btn.dataset.slot);
  closeModal();
  destroyFieldBuilding(slotId);
});

/* ============================================================
   CITY SCENE
============================================================ */
function openBuildingsWindow(slotId){
  const frameImg = "assets/buldings.png";
  const closeBtnImg = "assets/salirbutton.png";

  const data = builtSlots[slotId];
  const alreadyBuilt = data && data.state === "built";
  const isBusy = data && (data.state === "building" || data.state === "upgrading");

  // Edificios que pueden construirse múltiples veces
  const MULTI_BUILD = new Set(["home", "barrack"]);

  // Edificios únicos ya presentes en cualquier slot (built, building o upgrading)
  const alreadyBuiltKeys = new Set(
    Object.values(builtSlots)
      .filter(d => d && d.building && (d.state === "built" || d.state === "building" || d.state === "upgrading"))
      .map(d => d.building)
  );

  const cards = Object.entries(BUILDINGS).map(([key, def])=>{
    // no mostrar prebuilt en lista
    if(key === "fortress" || key === "eggdragon") return "";

    // ocultar edificios únicos que ya están construidos en la ciudad
    const isUnique    = !MULTI_BUILD.has(key);
    const uniqueBuilt = isUnique && alreadyBuiltKeys.has(key);
    if(uniqueBuilt) return "";

    const can      = canBuild(def.cost, playerResources);
    const disabled = (alreadyBuilt || isBusy || !can) ? "disabled" : "";
    const btnText  = alreadyBuilt ? "Built" : (isBusy ? "Busy..." : "Build");

    return `
      <div class="cb-card">
        <img class="cb-icon-img" src="${def.icon}" alt="${def.name}">
        <div class="cb-title">${def.name}</div>
        <div class="cb-desc">${def.desc}</div>

        <div class="cb-costs">
          <div class="cb-cost"><span class="cb-cost-ico"><img src="assets/ui_icon_lumber.png" class="res-icon-inline"></span><span class="cb-cost-txt">${def.cost.wood ?? 0}</span></div>
          <div class="cb-cost"><span class="cb-cost-ico"><img src="assets/ui_icon_food.png" class="res-icon-inline"></span><span class="cb-cost-txt">${def.cost.food ?? 0}</span></div>
          <div class="cb-cost"><span class="cb-cost-ico"><img src="assets/ui_icon_stone.png" class="res-icon-inline"></span><span class="cb-cost-txt">${def.cost.stone ?? 0}</span></div>
          <div class="cb-cost"><span class="cb-cost-ico"><img src="assets/ui_icon_metal.png" class="res-icon-inline"></span><span class="cb-cost-txt">${def.cost.iron ?? 0}</span></div>
        </div>

        <div style="margin-top:10px; font-weight:800; color:rgba(0,0,0,.65);">
          ⏳ Time: ${formatTime(def.buildTimeSec ?? 20)}
        </div>

        <button class="cb-build btn btn-primary"
                data-context="city"
                data-slot="${slotId}"
                data-building="${key}"
                ${disabled}>
          ${btnText}
        </button>

        ${(!can && !alreadyBuilt && !isBusy) ? `<div style="margin-top:8px;color:#8b0000;font-weight:800;">Not enough resources.</div>` : ""}
      </div>
    `;
  }).join("");

  const html = `
    <div class="cb-frame" style="background-image:url('${frameImg}')">
      <button class="buildings-close" data-close="modal" aria-label="Cerrar">
        <img src="${closeBtnImg}" alt="X">
      </button>

      <div class="cb-titlebar">City • Build</div>

      <div class="cb-grid" style="
        max-height: 75vh;
        overflow-y: auto;
        display: flex;
        flex-direction: column;
        gap: 18px;
        padding: 8px 12px 16px 12px;
      ">
        ${cards}
      </div>
    </div>
  `;

  openModal("", html, "big");
  updateResourcesUI();
}
function openFortressUpgradeWindow(slotId){
  const frameImg = "assets/buldings.png";
  const closeBtnImg = "assets/salirbutton.png";

  const data = builtSlots[slotId];
  if(!data || data.state !== "built") return;

  const def = BUILDINGS.fortress;
  const name = def?.name || "Fortress";

  const currentLevel = data.level ?? 1;
  const maxed = currentLevel >= BUILDING_MAX_LEVEL;

  const cost = getUpgradeCost("fortress", currentLevel);
  const timeSec = getUpgradeTimeSec("fortress", currentLevel);
  const can = canBuild(cost, playerResources);

  const html = `
    <div class="cb-frame" style="background-image:url('${frameImg}')">
      <button class="buildings-close" data-close="modal" aria-label="Cerrar">
        <img src="${closeBtnImg}" alt="X">
      </button>

      <div class="cb-titlebar">Fortress</div>

      <div class="cb-card" style="margin: 24px auto; width: min(320px, 92%);">
        <img class="cb-icon-img" src="${def?.icon || ""}" alt="${name}">
        <div class="cb-title">${name}</div>
        <div class="cb-desc">Level: <b>${currentLevel}</b> ${maxed ? "(MAX)" : `→ <b>${currentLevel+1}</b>`}</div>

        <div class="cb-costs" style="margin-top:10px;">
          <div class="cb-cost"><span class="cb-cost-ico"><img src="assets/ui_icon_lumber.png" class="res-icon-inline"></span><span class="cb-cost-txt">${cost.wood}</span></div>
          <div class="cb-cost"><span class="cb-cost-ico"><img src="assets/ui_icon_food.png" class="res-icon-inline"></span><span class="cb-cost-txt">${cost.food}</span></div>
          <div class="cb-cost"><span class="cb-cost-ico"><img src="assets/ui_icon_stone.png" class="res-icon-inline"></span><span class="cb-cost-txt">${cost.stone}</span></div>
          <div class="cb-cost"><span class="cb-cost-ico"><img src="assets/ui_icon_metal.png" class="res-icon-inline"></span><span class="cb-cost-txt">${cost.iron}</span></div>
        </div>

        <div style="margin-top:10px; font-weight:900; color:rgba(0,0,0,.65);">
          ⏳ Time: ${formatTime(timeSec)}
        </div>

        <button class="cb-upgrade btn btn-primary"
                data-slot="${slotId}"
                ${(!can || maxed) ? "disabled" : ""}>
          ${maxed ? "MAX" : "Upgrade"}
        </button>

        ${(!can && !maxed) ? `<div style="margin-top:8px;color:#8b0000;font-weight:800;">Not enough resources.</div>` : ""}
      </div>
    </div>
  `;

  openModal("", html, "big");
  updateResourcesUI();
}


