function openDragonKeepWindow(slotId){
  const frameImg    = "assets/buldings.png";
  const closeBtnImg = "assets/salirbutton.png";

  const data = builtSlots[slotId];
  if(!data || data.state !== "built") return;

  const currentLevel = data.level ?? 1;
  const maxed = currentLevel >= BUILDING_MAX_LEVEL;
  const name  = "Great Dragon";

  // ✅ FIX: Si el dragón es adulto (nivel 8+) y tiene toda la armadura, mostrar imagen con armadura
  const _allArmorOwned = ["helmet","body","claws","tail"].every(k => playerDragonArmor[k]);
  const _isAdult = currentLevel >= DRAGON_EVOLUTION.adultAt;
  const stageImg = (_isAdult && _allArmorOwned)
    ? "assets/adultdragonconarmadura.png"
    : getEggdragonModalImageForLevel(currentLevel);
  const cost  = getUpgradeCost("eggdragon", currentLevel);
  const timeSec = getUpgradeTimeSec("eggdragon", currentLevel);
  const can   = canBuild(cost, playerResources);

  /* ---- Piezas de armadura ---- */
  const ARMOR_PIECES = [
    { key:"helmet", label:"Great Dragon Armor: Helmet", img:"assets/Great_Dragon_Armor_Helmet.png" },
    { key:"body",   label:"Great Dragon Armor: Body",   img:"assets/Great_Dragon_Armor_Body.png"   },
    { key:"claws",  label:"Great Dragon Armor: Claws",  img:"assets/Great_Dragon_Armor_Claws.png"  },
    { key:"tail",   label:"Great Dragon Armor: Tail",   img:"assets/Great_Dragon_Armor_Tail.png"   }
  ];

  const allOwned = ARMOR_PIECES.every(p => playerDragonArmor[p.key]);

  function armorCardHtml(piece){
    const owned = playerDragonArmor[piece.key];
    return `
      <div class="dka-card ${owned ? "dka-owned" : "dka-locked"}">
        ${owned ? `<div class="dka-check">✓</div>` : ""}
        <div class="dka-img-wrap">
          ${owned
            ? `<img src="${piece.img}" alt="${piece.label}" onerror="this.style.display='none';this.nextElementSibling.style.display='flex'">`
            : ""
          }
          <div class="dka-lock" style="${owned ? "display:none" : ""}">🔒</div>
        </div>
        <div class="dka-label">${piece.label}</div>
      </div>`;
  }

  const html = `
    <style>
      /* ── Dragon Keep modal ── */
      .dk-modal-wrap{
        position:relative;
        background-image:url('${frameImg}');
        background-size:100% 100%;
        background-repeat:no-repeat;
        width:min(820px,94vw);
        min-height:480px;
        margin:0 auto;
        padding:16px 28px 32px;
        box-sizing:border-box;
        font-family:'Cinzel Decorative',Georgia,serif;
      }
      .dk-close-btn{
        position:absolute; top:14px; right:18px;
        background:none; border:none; cursor:pointer; z-index:10;
      }
      .dk-close-btn img{ width:36px; height:36px; }
      .dk-titlebar{
        text-align:center;
        font-size:15px; font-weight:900;
        color:#f5e3b0;
        text-shadow:0 1px 4px #000;
        margin-bottom:14px;
        letter-spacing:1px;
      }
      /* ── Tabs ── */
      .dk-tabs{
        display:flex; gap:6px;
        background:#1a1208;
        border-radius:6px;
        padding:6px 8px;
        margin-bottom:20px;
      }
      .dk-tab{
        flex:1; padding:8px 0; border:none; border-radius:5px;
        font-size:13px; font-weight:800; cursor:pointer;
        color:#bfab82; background:transparent;
        letter-spacing:.5px; transition:background .2s,color .2s;
      }
      .dk-tab.active{
        background:#d4670a;
        color:#fff;
        box-shadow:0 2px 8px rgba(212,103,10,.5);
      }
      /* ── Upgrade tab ── */
      .dk-upgrade-panel{ display:none; }
      .dk-upgrade-panel.visible{ display:block; }
      .dk-upgrade-card{
        background:rgba(0,0,0,.35);
        border-radius:10px;
        padding:18px 22px;
        display:flex; flex-direction:column; align-items:center; gap:8px;
        max-width:340px; margin:0 auto;
      }
      .dk-upgrade-card img{ width:110px; height:auto; }
      .dk-upgrade-card .dku-title{ color:#f5e3b0; font-size:16px; font-weight:900; }
      .dk-upgrade-card .dku-level{ color:#ccc; font-size:13px; }
      .dk-costs{ display:flex; gap:10px; flex-wrap:wrap; justify-content:center; margin-top:4px; }
      .dk-cost{ display:flex; align-items:center; gap:4px; color:#f0e0b0; font-size:13px; font-weight:700; }
      .dk-cost img{ width:20px !important; height:20px !important; object-fit:contain; vertical-align:middle; }
      .dk-upgrade-btn{
        margin-top:10px; padding:10px 40px;
        background:linear-gradient(180deg,#e8a020,#b26a00);
        border:2px solid #f5c64a; border-radius:8px;
        color:#fff; font-weight:900; font-size:14px; cursor:pointer;
        letter-spacing:.8px; transition:opacity .2s;
      }
      .dk-upgrade-btn:disabled{ opacity:.4; cursor:not-allowed; }
      .dk-no-res{ color:#cc3333; font-size:12px; font-weight:800; margin-top:4px; }
      /* ── Armor tab ── */
      .dk-armor-panel{ display:none; }
      .dk-armor-panel.visible{ display:block; }
      .dk-armor-title{ text-align:center; color:#f5e3b0; font-size:17px; font-weight:900; margin-bottom:18px; }
      .dka-grid{
        display:grid;
        grid-template-columns:repeat(4,1fr);
        gap:12px;
        justify-items:center;
      }
      @media(max-width:560px){
        .dka-grid{ grid-template-columns:repeat(2,1fr); }
      }
      .dka-card{
        position:relative;
        background:rgba(30,20,5,.6);
        border:2px solid #5a4010;
        border-radius:10px;
        padding:14px 10px 12px;
        width:100%; max-width:155px;
        display:flex; flex-direction:column; align-items:center; gap:8px;
        transition:border-color .2s;
      }
      .dka-card.dka-owned{ border-color:#c8860a; background:rgba(50,30,0,.7); }
      .dka-card.dka-locked{ opacity:.7; }
      .dka-check{
        position:absolute; top:-8px; right:-8px;
        width:22px; height:22px; border-radius:50%;
        background:#22aa44; color:#fff;
        font-size:13px; font-weight:900;
        display:flex; align-items:center; justify-content:center;
        border:2px solid #fff; box-shadow:0 1px 4px rgba(0,0,0,.5);
      }
      .dka-img-wrap{
        width:72px; height:72px;
        display:flex; align-items:center; justify-content:center;
      }
      .dka-img-wrap img{ max-width:100%; max-height:100%; object-fit:contain; }
      .dka-lock{ font-size:30px; line-height:1; }
      .dka-label{
        font-size:11px; font-weight:800; color:#c8a050;
        text-align:center; line-height:1.3;
      }
      .dka-card.dka-owned .dka-label{ color:#f0c060; }
      .dka-hint{
        margin-top:18px;
        background:rgba(0,0,0,.35);
        border-radius:8px;
        padding:10px 16px;
        text-align:center;
        color:#c8a050; font-size:12px; font-style:italic;
        border:1px solid #5a4010;
      }
      .dka-complete{
        margin-top:18px; text-align:center;
        color:#f5e3b0; font-size:13px; font-weight:800;
        text-shadow:0 0 8px rgba(255,200,50,.8);
      }
    </style>

    <div class="dk-modal-wrap">
      <button class="dk-close-btn" data-close="modal" aria-label="Cerrar">
        <img src="${closeBtnImg}" alt="X">
      </button>

      <div class="dk-titlebar">Dragon Keep</div>

      <div class="dk-tabs">
        <button class="dk-tab active" id="dkTabUpgrade" onclick="dkSwitchTab('upgrade')">Upgrade</button>
        <button class="dk-tab" id="dkTabArmor" onclick="dkSwitchTab('armor')">Dragon Armor</button>
      </div>

      <!-- ── UPGRADE PANEL ── -->
      <div class="dk-upgrade-panel visible" id="dkPanelUpgrade">
        <div class="dk-upgrade-card">
          <img src="${stageImg}" alt="${name}" onerror="this.src='assets/eggdragon.png'">
          <div class="dku-title">Great Dragon</div>
          <div class="dku-level">Level: <b>${currentLevel}</b> ${maxed ? "(MAX)" : `→ <b>${currentLevel+1}</b>`}</div>
          <div class="dk-costs">
            <div class="dk-cost"><img src="assets/ui_icon_lumber.png" class="res-icon-inline"> ${cost.wood}</div>
            <div class="dk-cost"><img src="assets/ui_icon_food.png" class="res-icon-inline"> ${cost.food}</div>
            <div class="dk-cost"><img src="assets/ui_icon_stone.png" class="res-icon-inline"> ${cost.stone}</div>
            <div class="dk-cost"><img src="assets/ui_icon_metal.png" class="res-icon-inline"> ${cost.iron}</div>
          </div>
          <div style="color:#aaa;font-size:12px;">⏳ ${formatTime(timeSec)}</div>
          <button class="dk-upgrade-btn" data-slot="${slotId}" onclick="startDragonUpgrade(${slotId})" ${(!can||maxed)?"disabled":""}>
            ${maxed ? "MAX" : "Upgrade"}
          </button>
          ${(!can&&!maxed)?`<div class="dk-no-res">Not enough resources.</div>`:""}
          ${(()=>{
            const s = GREAT_DRAGON_STATS[Math.min(currentLevel, 10) - 1];
            const sNext = !maxed ? GREAT_DRAGON_STATS[Math.min(currentLevel + 1, 10) - 1] : null;
            if(!s) return '';
            const fmt = n => n === 0 ? '—' : n.toLocaleString();
            const arrow = (a, b) => (sNext && a !== b) ? ` <span style="color:#f5c464">→ ${fmt(b)}</span>` : '';
            return `
            <div style="width:150%;margin-top:14px;border-radius:8px;overflow:hidden;border:1px solid rgba(212,167,10,0.4);">
              <div style="background:rgba(180,110,5,0.5);color:#fde68a;font-weight:900;font-size:11px;text-align:center;padding:5px 0;letter-spacing:.5px;">
                 GREAT DRAGON STATS
              </div>
              <table style="width:100%;border-collapse:collapse;text-align:center;color:#e8d9b0;font-size:11px;font-family:Arial,sans-serif;">
                <thead>
                  <tr style="background:rgba(0,0,0,0.3);color:#c8a050;font-size:10px;">
                    <th style="padding:4px 2px;">Melee</th>
                    <th style="padding:4px 2px;">Ranged</th>
                    <th style="padding:4px 2px;">Defense</th>
                    <th style="padding:4px 2px;">Life</th>
                    <th style="padding:4px 2px;">Speed</th>
                    <th style="padding:4px 2px;">Range</th>
                  </tr>
                </thead>
                <tbody>
                  <tr style="background:rgba(0,0,0,0.2);">
                    <td style="padding:5px 2px;">${fmt(s.melee)}${arrow(s.melee, sNext?.melee)}</td>
                    <td style="padding:5px 2px;">${fmt(s.ranged)}${arrow(s.ranged, sNext?.ranged)}</td>
                    <td style="padding:5px 2px;">${fmt(s.defense)}${arrow(s.defense, sNext?.defense)}</td>
                    <td style="padding:5px 2px;">${fmt(s.life)}${arrow(s.life, sNext?.life)}</td>
                    <td style="padding:5px 2px;">${fmt(s.speed)}</td>
                    <td style="padding:5px 2px;">${fmt(s.range)}</td>
                  </tr>
                </tbody>
              </table>
            </div>`;
          })()}
        </div>
      </div>

      <!-- ── ARMOR PANEL ── -->
      <div class="dk-armor-panel" id="dkPanelArmor">
        <div class="dk-armor-title">Great Dragon Armor</div>
        <div class="dka-grid">
          ${ARMOR_PIECES.map(p => armorCardHtml(p)).join("")}
        </div>
        ${allOwned
          ? `<div class="dka-complete"> Full Dragon Armor unlocked! Maximum power active.</div>`
          : `<div class="dka-hint">Collect all four pieces of the Great Dragon Armor to unlock its full power.</div>`
        }
      </div>
    </div>
  `;

  openModal("", html, "big");
  updateResourcesUI();
}

/* ── Tab switcher para Dragon Keep ── */
function dkSwitchTab(tab){
  const upgrade = document.getElementById("dkPanelUpgrade");
  const armor   = document.getElementById("dkPanelArmor");
  const tabU    = document.getElementById("dkTabUpgrade");
  const tabA    = document.getElementById("dkTabArmor");
  if(!upgrade || !armor) return;
  if(tab === "upgrade"){
    upgrade.classList.add("visible");    armor.classList.remove("visible");
    tabU.classList.add("active");        tabA.classList.remove("active");
  } else {
    armor.classList.add("visible");      upgrade.classList.remove("visible");
    tabA.classList.add("active");        tabU.classList.remove("active");
  }
}

/* ── Wrapper de upgrade llamado desde el botón ── */
function startDragonUpgrade(slotId){
  startUpgrade(slotId);
  const dataAfter = builtSlots[slotId];
  // Si el upgrade arrancó, cerrar el modal
  if(dataAfter && dataAfter.state === 'upgrading'){
    closeModal();
  } else {
    // No arrancó (bloqueado), reabrir para mostrar mensaje
    setTimeout(()=>{ openDragonKeepWindow(slotId); }, 200);
  }
}



