let mapViewEl = null;
let mapWrapperEl = null;
let mapZonesEl = null;
let mapZones = [];
let mapInitialized = false;

// Variables para el drag
let isDragging = false;
let startX = 0;
let startY = 0;
let currentX = 0;
let currentY = 0;
let mapX = 0;
let mapY = 0;

function saveMapZones(){
  try {
    // NO guardar enemies: son pesados y superan el límite de localStorage
    // Se regeneran automáticamente al cargar desde type + level
    const toSave = mapZones.map(z => ({
      id: z.id, typeId: z.typeId, name: z.name, icon: z.icon, type: z.type,
      level: z.level, x: z.x, y: z.y, coordX: z.coordX, coordY: z.coordY,
      totalPower: z.totalPower
    }));
    const json = JSON.stringify(toSave);
    const compressed = LZString.compress(json);
    localStorage.setItem('mapZones_v7', compressed);
    console.log(`💾 Zones saved: ${toSave.length} zones, ${(json.length/1024).toFixed(1)}KB → ${(compressed.length/1024).toFixed(1)}KB comprimido`);
  } catch(e) {
    console.warn('Error saving mapZones:', e);
  }
}

function loadMapZones(){
  try {
    const savedRaw = localStorage.getItem('mapZones_v7');
    if(!savedRaw) return false;
    // ✅ descomprimir si está comprimido, o parsear directo si es dato viejo
    let savedStr = savedRaw;
    try {
      const dec = LZString.decompress(savedRaw);
      if(dec && dec.length > 0) savedStr = dec;
    } catch(e) { /* dato viejo sin comprimir */ }
    const parsed = JSON.parse(savedStr);
    if(!parsed || !parsed.length) return false;
    // Regenerar enemies desde type+level (no se guardan para no superar límite localStorage)
    mapZones = parsed.map(z => {
      if(z.type !== 'fortress' && z.type !== 'other_fortress'){
        z.enemies = generateZoneEnemies(z.type, z.level);
        z.totalPower = calculateZoneTotalPower(z.enemies);
      }
      return z;
    });
    console.log(`✅ Loaded ${mapZones.length} zones from localStorage`);
    return true;
  } catch(e) { console.warn('Error loading mapZones:', e); return false; }
}

// ✅ Sync fortress in mapZones with current playerCity coords
function syncFortressPosition(){
  // uses global MAP_GRID_SIZE
  // uses global MAP_GRID_CELL
  let fort = mapZones.find(z => z.type === 'fortress');
  
  // If fortress not found in cache, add it
  if(!fort){
    const col = Math.floor((playerCity.coordX / MAP_COORD_MAX) * MAP_GRID_SIZE);
    const row = Math.floor((playerCity.coordY / MAP_COORD_MAX) * MAP_GRID_SIZE);
    fort = {
      id: 'player_fortress', typeId: 'fortress', name: playerCity.name,
      icon: 'assets/Fortress.png', type: 'fortress', level: 1,
      x: col * MAP_GRID_CELL + MAP_GRID_CELL / 2, y: row * MAP_GRID_CELL + MAP_GRID_CELL / 2,
      coordX: playerCity.coordX, coordY: playerCity.coordY
    };
    mapZones.push(fort);
    console.log(`🏰 Fortress added to mapZones at [${fort.coordX}:${fort.coordY}]`);
    saveMapZones();
    return;
  }
  
  // Update name from session
  fort.name = playerCity.name;
  
  // If coords match, no need to move
  if(fort.coordX === playerCity.coordX && fort.coordY === playerCity.coordY) return;
  
  // Recalculate position
  const col = Math.floor((playerCity.coordX / MAP_COORD_MAX) * MAP_GRID_SIZE);
  const row = Math.floor((playerCity.coordY / MAP_COORD_MAX) * MAP_GRID_SIZE);
  fort.coordX = playerCity.coordX;
  fort.coordY = playerCity.coordY;
  fort.x = col * MAP_GRID_CELL + MAP_GRID_CELL / 2;
  fort.y = row * MAP_GRID_CELL + MAP_GRID_CELL / 2;
  
  console.log(`🏰 Fortress position synced to [${fort.coordX}:${fort.coordY}]`);
  saveMapZones();
}

function initMapSystem(){
  if(mapInitialized) return;
  
  mapViewEl = document.getElementById("mapView");
  mapWrapperEl = document.getElementById("mapWrapper");
  mapZonesEl = document.getElementById("mapZones");

  // Cargar zonas guardadas o generar nuevas (ANTES de centrar)
  if(!loadMapZones()){
    generateMapZones();
    saveMapZones();
  }

  // ✅ Sync fortress position with current playerCity (may differ from cache)
  syncFortressPosition();

  // Setup drag handlers
  setupMapDrag();

  // Setup search
  setupMapSearch();

  mapInitialized = true;

  // ✅ Restaurar posición del mapa guardada, o centrar si no hay ninguna
  if(window._savedMapPosition){
    mapX = window._savedMapPosition.x;
    mapY = window._savedMapPosition.y;
    window._savedMapPosition = null;
    updateMapPosition();
  }
}

function centerMap(){
  // Centrar el mapa en el grid 5x5 (tile central = offset 2x)
  if(!mapViewEl) return;
  const viewRect = mapViewEl.getBoundingClientRect();
  mapX = -viewRect.width * 2;
  mapY = -viewRect.height * 2;
  updateMapPosition();
}

function setupMapDrag(){
  mapViewEl.addEventListener('mousedown', onMapMouseDown);
  document.addEventListener('mousemove', onMapMouseMove);
  document.addEventListener('mouseup', onMapMouseUp);
  
  // Touch events para móvil
  mapViewEl.addEventListener('touchstart', onMapTouchStart);
  document.addEventListener('touchmove', onMapTouchMove);
  document.addEventListener('touchend', onMapTouchEnd);
}

// Umbral de píxeles para distinguir click de drag
const DRAG_THRESHOLD = 6;
let dragMoved = false;
let mouseDownTarget = null;
let mouseDownX = 0;
let mouseDownY = 0;

function onMapMouseDown(e){
  if(e.target.closest('.map-search')) return;

  mouseDownTarget = e.target;
  mouseDownX = e.clientX;
  mouseDownY = e.clientY;
  dragMoved = false;
  isDragging = true;
  mapViewEl.classList.add('dragging');

  startX = e.clientX - mapX;
  startY = e.clientY - mapY;
}

function onMapMouseMove(e){
  if(!isDragging) return;

  // Detectar si se movió lo suficiente para ser un drag real
  const dx = e.clientX - mouseDownX;
  const dy = e.clientY - mouseDownY;
  if(!dragMoved && Math.sqrt(dx*dx + dy*dy) > DRAG_THRESHOLD){
    dragMoved = true;
  }

  e.preventDefault();

  currentX = e.clientX - startX;
  currentY = e.clientY - startY;

  const bounds = getMapBounds();
  mapX = Math.max(bounds.minX, Math.min(bounds.maxX, currentX));
  mapY = Math.max(bounds.minY, Math.min(bounds.maxY, currentY));

  updateMapPosition();
}

function onMapMouseUp(e){
  if(!isDragging) return;
  isDragging = false;
  mapViewEl.classList.remove('dragging');

  // Si NO hubo drag real y el click fue sobre una zona, ejecutar el click de zona
  if(!dragMoved && mouseDownTarget){
    const zoneEl = mouseDownTarget.closest('.map-zone');
    if(zoneEl){
      zoneEl.dispatchEvent(new MouseEvent('click', { bubbles: false }));
    }
  }
  mouseDownTarget = null;
}

function onMapTouchStart(e){
  if(e.target.closest('.map-search')) return;

  mouseDownTarget = e.target;
  const touch = e.touches[0];
  mouseDownX = touch.clientX;
  mouseDownY = touch.clientY;
  dragMoved = false;
  isDragging = true;
  mapViewEl.classList.add('dragging');

  startX = touch.clientX - mapX;
  startY = touch.clientY - mapY;
}

function onMapTouchMove(e){
  if(!isDragging) return;

  const touch = e.touches[0];
  const dx = touch.clientX - mouseDownX;
  const dy = touch.clientY - mouseDownY;
  if(!dragMoved && Math.sqrt(dx*dx + dy*dy) > DRAG_THRESHOLD){
    dragMoved = true;
  }

  e.preventDefault();

  currentX = touch.clientX - startX;
  currentY = touch.clientY - startY;

  const bounds = getMapBounds();
  mapX = Math.max(bounds.minX, Math.min(bounds.maxX, currentX));
  mapY = Math.max(bounds.minY, Math.min(bounds.maxY, currentY));

  updateMapPosition();
}

function onMapTouchEnd(e){
  if(!isDragging) return;
  isDragging = false;
  mapViewEl.classList.remove('dragging');

  if(!dragMoved && mouseDownTarget){
    const zoneEl = mouseDownTarget.closest('.map-zone');
    if(zoneEl){
      zoneEl.dispatchEvent(new MouseEvent('click', { bubbles: false }));
    }
  }
  mouseDownTarget = null;
}

function getMapBounds(){
  if(!mapViewEl || !mapWrapperEl || !mapZonesEl) return { minX: 0, maxX: 0, minY: 0, maxY: 0 };
  
  const viewRect = mapViewEl.getBoundingClientRect();
  const wrapperWidth  = mapZonesEl.offsetWidth;
  const wrapperHeight = mapZonesEl.offsetHeight;
  
  return {
    minX: -(wrapperWidth  - viewRect.width),
    maxX: 0,
    minY: -(wrapperHeight - viewRect.height),
    maxY: 0
  };
}

function updateMapPosition(){
  if(!mapWrapperEl) return;
  
  // Usar píxeles en lugar de porcentajes para mejor control
  mapWrapperEl.style.transform = `translate(${mapX}px, ${mapY}px)`;
}

// Generar enemigos para una zona según su tipo y nivel
function generateZoneEnemies(zoneType, level){
  const enemies = {};
  
  if(zoneType === 'camp'){
    // CAMPAMENTOS ANTHROPUS: Usar tabla de PODER
    Object.keys(ANTHROPUS_CAMP_POWER).forEach(troopKey => {
      const powerAtLevel = ANTHROPUS_CAMP_POWER[troopKey][level];
      if(powerAtLevel > 0){
        const troopInfo = ANTHROPUS_TROOPS_INFO[troopKey];
        const quantity = Math.floor(powerAtLevel / troopInfo.powerPerUnit);
        if(quantity > 0){
          enemies[troopKey] = {
            name: troopInfo.name,
            icon: troopInfo.icon,
            quantity: quantity,
            power: powerAtLevel,
            // ✅ STATS COMPLETAS
            meleeAtk: troopInfo.meleeAtk,
            def: troopInfo.def,
            life: troopInfo.life,
            speed: troopInfo.speed,
            range: troopInfo.range,
            rangeAtk: troopInfo.rangeAtk
          };
        }
      }
    });
  } else {
    // ZONAS SALVAJES: Usar tabla de CANTIDAD
    Object.keys(WILDERNESS_TROOP_COUNT).forEach(troopKey => {
      const quantityAtLevel = WILDERNESS_TROOP_COUNT[troopKey][level];
      if(quantityAtLevel > 0){
        const troopInfo = ANTHROPUS_TROOPS_INFO[troopKey];
        enemies[troopKey] = {
          name: troopInfo.name,
          icon: troopInfo.icon,
          quantity: quantityAtLevel,
          power: quantityAtLevel * troopInfo.powerPerUnit,
          // ✅ STATS COMPLETAS
          meleeAtk: troopInfo.meleeAtk,
          def: troopInfo.def,
          life: troopInfo.life,
          speed: troopInfo.speed,
          range: troopInfo.range,
          rangeAtk: troopInfo.rangeAtk
        };
      }
    });
  }
  
  return enemies;
}

// Calcular poder total de una zona basado en sus enemigos
function calculateZoneTotalPower(enemies){
  let totalPower = 0;
  Object.values(enemies).forEach(enemy => {
    totalPower += enemy.power;
  });
  return totalPower;
}

// ✅ Seeded PRNG so all players generate the same map
function seededRandom(seed){
  let s = seed;
  return function(){
    s = (s * 1664525 + 1013904223) & 0xFFFFFFFF;
    return (s >>> 0) / 0xFFFFFFFF;
  };
}

// Generar zonas distribuidas uniformemente por todo el mapa
function generateMapZones(){
  mapZones = [];
  
  let zoneId = 0;
  const MAP_SEED = 42424242; // Fixed seed — same map for everyone
  const rng = seededRandom(MAP_SEED);
  
  // Generar 1024 zonas (32x32 grid)
  // uses global MAP_GRID_SIZE
  // uses global MAP_GRID_CELL
  
  // Generate ALL cells first (same for every player)
  for(let row = 0; row < MAP_GRID_SIZE; row++){
    for(let col = 0; col < MAP_GRID_SIZE; col++){
      const zoneType = ZONE_TYPES[Math.floor(rng() * ZONE_TYPES.length)];
      const level = Math.floor(rng() * 10) + 1;
      
      const x = col * MAP_GRID_CELL + MAP_GRID_CELL / 2;
      const y = row * MAP_GRID_CELL + MAP_GRID_CELL / 2;
      
      const coordX = Math.floor(x * MAP_COORD_MAX / 100);
      const coordY = Math.floor(y * MAP_COORD_MAX / 100);
      
      const enemies = generateZoneEnemies(zoneType.type, level);
      const totalPower = calculateZoneTotalPower(enemies);
      
      mapZones.push({
        id: `zone_${zoneId}`,
        typeId: zoneType.id,
        name: zoneType.name,
        icon: zoneType.icon,
        type: zoneType.type,
        level: level,
        x: x,
        y: y,
        coordX: coordX,
        coordY: coordY,
        enemies: enemies,
        totalPower: totalPower
      });
      
      zoneId++;
    }
  }
  
  console.log(`✅ Generated ${mapZones.length} zones (seeded)`);
  
  // Now REPLACE the cell at player's fortress position
  const fortressCoordX = playerCity.coordX;
  const fortressCoordY = playerCity.coordY;
  const fortressGridCol = Math.floor((fortressCoordX / MAP_COORD_MAX) * MAP_GRID_SIZE);
  const fortressGridRow = Math.floor((fortressCoordY / MAP_COORD_MAX) * MAP_GRID_SIZE);
  const fortressX = fortressGridCol * MAP_GRID_CELL + MAP_GRID_CELL / 2;
  const fortressY = fortressGridRow * MAP_GRID_CELL + MAP_GRID_CELL / 2;
  
  // Remove zone at fortress position
  mapZones = mapZones.filter(z => {
    const zCol = Math.floor((z.x - MAP_GRID_CELL / 2) / MAP_GRID_CELL + 0.5);
    const zRow = Math.floor((z.y - MAP_GRID_CELL / 2) / MAP_GRID_CELL + 0.5);
    return !(zCol === fortressGridCol && zRow === fortressGridRow);
  });
  
  // Add fortress
  mapZones.push({
    id: 'player_fortress',
    typeId: 'fortress',
    name: playerCity.name,
    icon: 'assets/Fortress.png',
    type: 'fortress',
    level: 1,
    x: fortressX,
    y: fortressY,
    coordX: fortressCoordX,
    coordY: fortressCoordY
  });
  
  console.log(`🏰 Fortress at [${fortressCoordX}:${fortressCoordY}] grid[${fortressGridCol},${fortressGridRow}]`);
  
  // Add other players if already loaded
  if(otherPlayerCities.length > 0) addOtherPlayerZones();
}

function renderMapZones(){
  if(!mapZonesEl) return;
  
  // Limpiar mapa
  mapZonesEl.innerHTML = '';
  
  console.log(`🗺️ Rendering ${mapZones.length} zones on map`);
  
  // Renderizar cada zona (incluye 1600 zonas + fortaleza)
  mapZones.forEach(zone => {
    const zoneElement = document.createElement('div');
    zoneElement.className = 'map-zone';
    zoneElement.style.position = 'absolute';
    zoneElement.style.left = `${zone.x}%`;
    zoneElement.style.top = `${zone.y}%`;
    zoneElement.style.transform = 'translate(-50%, -50%)';
    zoneElement.setAttribute('data-zone-id', zone.id);
    zoneElement.setAttribute('data-coord-x', zone.coordX);
    zoneElement.setAttribute('data-coord-y', zone.coordY);
    
    if(zone.type === 'fortress' || zone.type === 'other_fortress'){
      // FORTALEZA - propia u otro jugador
      zoneElement.classList.add('player-city');
      if(zone.type === 'other_fortress') zoneElement.classList.add('other-player-city');
      const fortSize = zone.type === 'fortress' ? 150 : 120;
      const imgSize = zone.type === 'fortress' ? 120 : 90;
      zoneElement.style.width = `${fortSize}px`;
      zoneElement.style.height = `${fortSize}px`;
      zoneElement.style.zIndex = zone.type === 'fortress' ? '99999' : '99998';
      zoneElement.style.background = 'transparent';
      zoneElement.style.border = 'none';
      zoneElement.style.borderRadius = '0';
      zoneElement.style.boxShadow = 'none';
      zoneElement.style.cursor = 'pointer';
      zoneElement.title = `${zone.name} [${zone.coordX}:${zone.coordY}]`;
      
      const nameColor = zone.type === 'fortress' ? '#4ade80' : '#f59e0b';
      
      zoneElement.innerHTML = `
        <div style="
          width: 100%;
          height: 100%;
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          position: relative;
        ">
          <!-- Nombre del jugador encima -->
          <div style="
            font-size: 11px;
            font-weight: 700;
            color: ${nameColor};
            text-shadow: 0 0 4px rgba(0,0,0,0.9), 0 1px 2px rgba(0,0,0,0.8);
            margin-bottom: 2px;
            white-space: nowrap;
            letter-spacing: 0.5px;
          ">${zone.name}</div>
          
          <!-- Imagen principal de la fortaleza -->
          <img src="${zone.icon}" 
               onerror="this.style.display='none'; this.parentElement.querySelector('.fallback-emoji').style.display='block';" 
               style="
                 width: ${imgSize}px;
                 height: ${imgSize}px;
                 object-fit: contain;
                 filter: drop-shadow(0 0 10px rgba(0,0,0,0.5));
                 margin-bottom: 2px;
                 position: relative;
                 z-index: 2;
               ">
          
          <!-- Emoji de respaldo si la imagen no carga -->
          <div class="fallback-emoji" style="
            display: none;
            font-size: ${zone.type === 'fortress' ? 80 : 60}px;
            text-shadow: 0 0 10px rgba(0,0,0,0.5);
            margin-bottom: 5px;
          ">🏰</div>
        </div>
      `;
      
      console.log(`🏰 Fortress rendered at ${zone.x.toFixed(1)}%, ${zone.y.toFixed(1)}% [${zone.coordX}:${zone.coordY}]`);
      
      
    } else {
      // ZONAS NORMALES (campamentos y zonas salvajes)
      zoneElement.style.width = '65px';
      zoneElement.style.height = '65px';
      zoneElement.style.zIndex = '100';
      zoneElement.style.cursor = 'pointer';
      
      // Determinar ícono correcto para campamentos según nivel
      let zoneIcon = zone.icon;
      let zoneName = zone.name;
      
      if(zone.type === 'camp'){
        zoneName = 'Anthropus Camp';
        
        // Cambiar imagen según el nivel
        if(zone.level >= 1 && zone.level <= 4){
          zoneIcon = 'assets/camp.png';
        } else if(zone.level >= 5 && zone.level <= 7){
          zoneIcon = 'assets/camp2.png';
        } else if(zone.level >= 8 && zone.level <= 10){
          zoneIcon = 'assets/camp3.png';
        }
      }
      
      zoneElement.title = `${zoneName} - Lv.${zone.level} [${zone.coordX}:${zone.coordY}]`;
      
      zoneElement.innerHTML = `
        <img src="${zoneIcon}" class="map-zone-icon" alt="${zoneName}">
        <div class="map-zone-coords">${zone.coordX}:${zone.coordY}</div>
        <div class="map-zone-level">${zone.level}</div>
      `;
    }
    
    // Evento de click
    zoneElement.addEventListener('click', (e) => {
      e.stopPropagation();
      onZoneClick(zone);
    });
    
    mapZonesEl.appendChild(zoneElement);
  });
  
  console.log(`✅ All ${mapZones.length} zones rendered successfully`);
  
  // VERIFICACIÓN ADICIONAL: Contar fortalezas renderizadas
  const fortressElements = mapZonesEl.querySelectorAll('.player-city');
  console.log(`🏰 Fortress elements found: ${fortressElements.length}`);
  
  if(fortressElements.length > 0){
    fortressElements.forEach((el, idx) => {
      const rect = el.getBoundingClientRect();
      const coordX = el.getAttribute('data-coord-x');
      const coordY = el.getAttribute('data-coord-y');
      console.log(`   Fortress ${idx + 1}: [${coordX}:${coordY}] | Position: ${el.style.left}, ${el.style.top} | Size: ${rect.width}x${rect.height}px | Visible: ${rect.width > 0 && rect.height > 0}`);
    });
  } else {
    console.error('❌ NO FORTRESS ELEMENTS RENDERED!');
  }
  
  // Agregar animación CSS si no existe
  if(!document.getElementById('fortress-animation-style')){
    const style = document.createElement('style');
    style.id = 'fortress-animation-style';
    style.textContent = `
      @keyframes pulse {
        0%, 100% { transform: scale(1); opacity: 1; }
        50% { transform: scale(1.5); opacity: 0.5; }
      }
    `;
    document.head.appendChild(style);
  }
}

function onZoneClick(zone){
  console.log("🎯 Zone clicked:", zone);
  
  if(zone.type === 'fortress'){
    showFortressModal(zone, true);
    return;
  }
  
  if(zone.type === 'other_fortress'){
    showFortressModal(zone, false);
    return;
  }
  
  // Mostrar modal con información de la zona
  showZoneInfoModal(zone);
}

