/* ============================================================
   ⚔️ PVP ATTACK SYSTEM
============================================================ */
async function initPvPAttack(zone){
  const targetUsername = zone.ownerName || zone.name;
  console.log(`⚔️ PvP: Preparing attack on ${targetUsername}`);

  // Fetch defender's troops from server
  const token = localStorage.getItem('ATLANTIS_TOKEN');
  try {
    const res = await fetch(`/api/game/defender/${encodeURIComponent(targetUsername)}`, {
      headers: { 'Authorization': 'Bearer ' + token }
    });
    const data = await res.json();

    if(!data.ok || !data.defender){
      alert(data.error || 'Could not load defender data');
      return;
    }

    const defender = data.defender;

    // Build a fake "zone" with defender's troops as enemies
    const pvpZone = {
      id: `pvp_${targetUsername}`,
      typeId: 'other_fortress',
      name: defender.username,
      icon: 'assets/Fortress.png',
      type: 'pvp',
      level: defender.fortressLevel || 1,
      coordX: defender.coordX,
      coordY: defender.coordY,
      totalPower: defender.power || 0,
      _pvp: true,
      _defenderUsername: defender.username,
      _defenderJugadorId: defender.jugadorId,
      _defenderResources: defender.resources || {},
      enemies: {}
    };

    // Convert defender troops to enemy format
    const troopQuantities = defender.troops || {};
    TROOPS.forEach(t => {
      const qty = troopQuantities[t.id] || 0;
      if(qty > 0){
        pvpZone.enemies[t.id] = {
          name: t.name,
          quantity: qty,
          meleeAtk: t.stats.atk,
          rangeAtk: t.stats.raa || 0,
          def: t.stats.def,
          life: t.stats.hp,
          speed: t.stats.spd,
          range: t.stats.ran || 0,
          power: t.stats.pow || 1,
          type: (t.stats.ran > 0) ? 'ranged' : 'melee'
        };
      }
    });

    // If defender has no troops, easy win
    if(Object.keys(pvpZone.enemies).length === 0){
      pvpZone.totalPower = 0;
    }

    console.log(`⚔️ PvP zone created for ${defender.username}:`, pvpZone);

    // Open troop selection modal targeting this PvP zone
    openTroopSelectionModal(pvpZone);

  } catch(e){
    console.error('⚔️ PvP error:', e);
    alert('Could not start PvP attack');
  }
}

// Override executeAttack to handle PvP results
const _originalExecuteAttack = typeof executeAttack === 'function' ? executeAttack : null;

function executeAttackWithPvP(){
  if(!currentAttackTarget){
    alert('No target selected.');
    return;
  }

  const totalSelected = Object.values(selectedTroopsForAttack).reduce((sum, qty) => sum + qty, 0);
  if(totalSelected === 0 && !dragonSentToBattle){
    alert('You must select at least 1 troop or send the dragon to attack.');
    return;
  }

  const isPvP = currentAttackTarget._pvp === true;

  console.log(`⚔️ Executing ${isPvP ? 'PvP' : 'PvE'} attack!`);

  window._dragonBattleBoost = dragonSentToBattle ? { atk:1.05, def:1.05, spd:1.05 } : null;
  const _dragonWasSent = dragonSentToBattle;
  const _generalWasSent = (typeof window.getSelectedGeneral === 'function') ? window.getSelectedGeneral() : null;

  // Simulate battle (works for both PvP and PvE since enemies format is the same)
  const battleResult = simulateBattle(selectedTroopsForAttack, currentAttackTarget);

  battleResult.dragonSent = _dragonWasSent;
  battleResult.generalUsed = (_generalWasSent && _generalWasSent.id !== 'none') ? _generalWasSent : null;
  battleResult._pvp = isPvP;

  if(isPvP){
    battleResult._defenderUsername = currentAttackTarget._defenderUsername;
  }

  console.log('Battle result:', battleResult);

  closeTroopSelectionModal();

  const messageId = addBattleMessage(battleResult);
  applyBattleResults(battleResult);

  // PvP: notify server of defender losses + loot
  if(isPvP){
    const defenderTroopLosses = {};
    if(battleResult.defenderLosses){
      Object.entries(battleResult.defenderLosses).forEach(([troopId, data]) => {
        if(data.lost > 0) defenderTroopLosses[troopId] = data.lost;
      });
    }

    // Calculate looted resources
    const resourcesLooted = {};
    if(battleResult.rewards){
      Object.entries(battleResult.rewards).forEach(([res, amt]) => {
        if(amt > 0 && res !== 'power') resourcesLooted[res] = amt;
      });
    }

    // Send to server
    const token = localStorage.getItem('ATLANTIS_TOKEN');
    fetch('/api/game/pvp-result', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
      body: JSON.stringify({
        defenderUsername: currentAttackTarget._defenderUsername,
        troopLosses: defenderTroopLosses,
        resourcesLooted: resourcesLooted
      })
    }).catch(e => console.warn('⚔️ PvP result sync failed:', e));

    // Socket notification to defender
    if(chatSocket && chatConnected){
      const ses = getSession();
      chatSocket.emit('pvp_attack', {
        attackerName: ses?.user || 'Unknown',
        defenderName: currentAttackTarget._defenderUsername,
        victory: battleResult.victory,
        resourcesLooted: resourcesLooted
      });
    }
  }

  saveGame();
}

function showZoneInfoModal(zone){
  const modal = document.getElementById('zoneInfoModal');
  if(!modal) return;
  
  // Guardar zona actual para el botón INFO
  currentZone = zone;
  
  // Determinar nombre según el tipo
  let displayName = zone.name;
  if(zone.type === 'camp'){
    displayName = 'ANTHROPUS CAMP';
  } else if(zone.type === 'wilderness'){
    displayName = zone.name.toUpperCase();
  }
  
  // Usar el poder REAL calculado de las tropas
  const zonePower = zone.totalPower || 0;
  
  // Actualizar contenido del modal
  document.getElementById('zoneInfoLevel').textContent = `Lv.${zone.level}`;
  document.getElementById('zoneInfoName').textContent = displayName;
  document.getElementById('zoneInfoPowerValue').textContent = zonePower.toLocaleString();
  document.getElementById('zoneInfoCoords').textContent = `[${zone.coordX}:${zone.coordY}]`;
  
  // Actualizar imagen
  const zoneImage = document.getElementById('zoneInfoImage');
  zoneImage.src = zone.icon;
  zoneImage.alt = displayName;
  
  // Mostrar modal
  modal.classList.remove('hidden');
  
  console.log(`📋 Zone info modal opened for: ${displayName} Lv.${zone.level} | Power: ${zonePower}`);
}

