      2:{wood:[6000],stone:[0,0],iron:[0,0],food:[1000],gold:[0,0]},
      3:{wood:[10000],stone:[500],iron:[0,0],food:[1500],gold:[0,0]},
      4:{wood:[14000],stone:[1000],iron:[0,0],food:[2000],gold:[200]},
