      2:{wood:[0,0],stone:[0,0],iron:[0,0],food:[6000],gold:[250]},
      3:{wood:[0,0],stone:[0,0],iron:[0,0],food:[10000],gold:[500]},
      4:{wood:[0,0],stone:[0,0],iron:[0,0],food:[14000],gold:[1000]},
      5:{wood:[0,0],stone:[0,0],iron:[0,0],food:[18000],gold:[1500]},
      6:{wood:[0,0],stone:[0,0],iron:[0,0],food:[28000],gold:[2500]},
      7:{wood:[0,0],stone:[0,0],iron:[0,0],food:[34000],gold:[3500]},
