// Aplicar resultados de batalla al juego
function applyBattleResults(battleResult, skipTroopDeduction = false){
  // Aplicar bajas del jugador (solo si NO viene de marcha)
  if (!skipTroopDeduction) {
    Object.keys(battleResult.playerCasualties).forEach(troopId => {
      const casualties = battleResult.playerCasualties[troopId].quantity;
      const troop = Object.values(TROOPS).find(t => t.id === troopId);
      if(troop && casualties > 0){
        troop.have = Math.max(0, (troop.have || 0) - casualties);
        console.log(`💀 Lost ${casualties} ${troop.name} (remaining: ${troop.have})`);
      }
    });
  }
  
  // Recalcular poder del jugador
  recalculatePlayerPower();
  
  // Si ganó, dar recompensas
  if(battleResult.victory && battleResult.rewards){
    playerResources.wood  = (playerResources.wood  || 0) + (battleResult.rewards.wood  || 0);
    playerResources.stone = (playerResources.stone || 0) + (battleResult.rewards.stone || 0);
    playerResources.iron  = (playerResources.iron  || 0) + (battleResult.rewards.iron  || 0);
    playerResources.food  = (playerResources.food  || 0) + (battleResult.rewards.food  || 0);
    playerResources.gold  = (playerResources.gold  || 0) + (battleResult.rewards.gold  || 0);
    
    // ── Aplicar item drops de campamentos ──
    if(battleResult.itemDrops && battleResult.itemDrops.length > 0){
      applyCampItemDrops(battleResult.itemDrops);
      saveGame();
    }
    console.log('🎁 Rewards collected:', battleResult.rewards);
    
    // NO ELIMINAR LA ZONA DEL MAPA (el usuario quiere que permanezca)
    /*
    // Eliminar la zona del mapa
    const zoneIndex = mapZones.findIndex(z => z.id === battleResult.targetZone.id);
    if(zoneIndex !== -1){
      mapZones.splice(zoneIndex, 1);
      console.log(`🗑️ Zone ${battleResult.targetZone.id} removed from map`);
      
      // Re-renderizar mapa
      renderMapZones();
    }
    */
  }
  
  // ✅ liberar el dragón (batalla ya terminó, puede volver a usarse)
  window._dragonBattleBoost = null;
  window._dragonOnMarch = false;

  // Actualizar UI
  updateResourcesUI();
  renderTroopsGrid();
  saveGame(); // ✅ guardar siempre al resolver una batalla
}

